  function prepareMobileTables(){$$('#content .table-wrap table').forEach(table=>{if(table.classList.contains('monthly-table'))return;const headers=[...table.querySelectorAll('thead th')].map((th,index)=>th.textContent.trim()||`ж¬„дҪҚ ${index+1}`);table.classList.add('mobile-card-table');[...table.querySelectorAll('tbody tr')].forEach(row=>[...row.children].forEach((cell,index)=>cell.dataset.label=headers[index]||''))})}
  async function renderCurrent() { try { state.view==='dashboard'?await renderDashboard():state.view==='schedules'?await renderEmployeeMonthlySchedule():state.view==='attendance'?await renderAttendanceRecords():state.view==='cashReceipts'?await renderCashReceipts():state.view==='tenderQuotations'?await window.TenderQuotes.render():state.view==='tenderContracts'?await window.TenderContracts.render():state.view==='websiteManager'?await window.WebsiteCenter.renderManager():state.view==='websiteNotifications'?await window.WebsiteCenter.renderNotifications():await renderTable(state.view);prepareMobileTables(); } catch(error) { $('#content').innerHTML=`<article class="panel empty">ијүе…ҘеӨұж•—пјҡ${esc(error.message)}</article>`; } }
